 * <p>
 * Implements preliminary checks for NaN and infinity followed by
 * the definitional formula:
 * <pre><code>
 * (a + bi)(c + di) = (ac - bd) + (ad + bc)i
 * </code></pre>
 * </p>
 * <p>
 * Returns {@link #NaN} if either this or <code>rhs</code> has one or more
 * NaN parts.
 * </p>
 * Returns {@link #INF} if neither this nor <code>rhs</code> has one or more
 * NaN parts and if either this or <code>rhs</code> has one or more
 * infinite parts and the other is non-zero.
 * </p>
 * <p>
 * Returns finite values in components of the result per the
 * definitional formula in all remaining cases.
 *  </p>
 *
 * @param rhs the other complex number
 * @return the complex number product
 * @throws NullPointerException if <code>rhs</code> is null
 */
public Complex multiply(Complex rhs) {
    if (isNaN() || rhs.isNaN()) {
        return NaN;
    }

    boolean thisHasInf = Double.isInfinite(real) || Double.isInfinite(imaginary);
    boolean rhsHasInf = Double.isInfinite(rhs.real) || Double.isInfinite(rhs.imaginary);

    if (thisHasInf || rhsHasInf) {
        // If both have infinities, result is NaN
        if (thisHasInf && rhsHasInf) {
            return NaN;
        }

        // If only one has infinities, but the other is zero, result is zero
        // Zero means both real and imaginary parts are 0.0
        if (thisHasInf && rhs.real == 0.0 && rhs.imaginary == 0.0) {
            return ZERO;
        }
        if (rhsHasInf && real == 0.0 && imaginary == 0.0) {
            return ZERO;
        }

        // Otherwise, the result contains infinities
        return INF;
    }

    return createComplex(real * rhs.real - imaginary * rhs.imaginary,
            real * rhs.imaginary + imaginary * rhs.real);
}

